script:
frappe.ui.form.on("Quotation", {

    after_save(frm) {
        validateDiscountRules(frm);
    },

    discount_amount(frm) {
        validateDiscountAmount(frm);
    },

    additional_discount_percentage(frm) {
        validateAdditionalDiscount(frm);
    },

    price_list(frm) {
        validatePriceListChange(frm);
    }
});

function applyDiscountPermissions(frm) {
    const userRoles = frappe.user_roles;

    console.log("Current User Roles:", userRoles);

    let maxDiscountPercentage = 0;
    let canChangePrice = false;
    let canApplyDiscount = true;
    let canApplyAmountDiscount = true;
    let isCoordinator = false;
    const topRoles = [
        "Sales Master Manager - ALVOIP",
        "Sales Master Manager - DMS",
        "Sales Master Manager - AVTECH",
        "Sales Manager - ALVOIP",
        "Sales Manager - DMS",
        "Sales Manager - AVTECH",
        "Product Manager - DMS",
        "Product Manager - ALVOIP",
        "Product Manager - AVTECH",
        "System Manager"
    ];

    const seniorRoles = [
            "Senior Sales - ALVOIP",
            "Senior Sales - DMS",
            "Senior Sales - AVTECH",
    ]

    const juniorRoles = [
        "Junior Sales - ALVOIP",
        "Junior Sales - DMS",
        "Junior Sales - AVTECH",
    ] 

    const coordinatorRole = [
        "Sales Coordinator - DMS",
        "Sales Coordinator - AVTECH",
        "Sales Coordinator - ALVOIP"
    ]

    const hasTopRole = userRoles.some(role => topRoles.includes(role));
    const hasSeniorRole = userRoles.some(role => seniorRoles.includes(role));
    const hasJuniorRole = userRoles.some(role => juniorRoles.includes(role));
    const hasCoordinatorRole = userRoles.some(role => coordinatorRole.includes(role)); 

    if (hasTopRole) {
        maxDiscountPercentage = 100; 
        canChangePrice = true;
        canApplyDiscount = true;
        canApplyAmountDiscount = true;
        console.log(" Top Roles - Full permissions");

    } else if (hasSeniorRole) {
        maxDiscountPercentage = 10;
        canChangePrice = true;
        canApplyDiscount = true;
        canApplyAmountDiscount = false; 
        console.log("Senior Sales - Max 10% discount");

    } else if (hasJuniorRole) {
        maxDiscountPercentage = 5;
        canChangePrice = false;
        canApplyDiscount = true;
        canApplyAmountDiscount = false; 
        console.log("Junior Sales - Max 5% discount");

    } else if (hasCoordinatorRole) {
        maxDiscountPercentage = 0;
        canChangePrice = false;
        canApplyDiscount = false;
        canApplyAmountDiscount = false;
        isCoordinator = true;
        console.log(`Sales Coordinator - Cannot apply discount ${hasCoordinatorRole}`);
    }

    frm.maxDiscountPercentageAllowed = maxDiscountPercentage;
    frm.canChangePrice = canChangePrice;
    frm.canApplyDiscount = canApplyDiscount;
    frm.canApplyAmountDiscount = canApplyAmountDiscount;

    frm.set_df_property("discount_amount", "read_only", !canApplyAmountDiscount);
    frm.set_df_property("additional_discount_percentage", "read_only", !canApplyDiscount);
    frm.set_df_property("price_list", "read_only", !canChangePrice);

    if (isCoordinator) {
        frm.set_df_property("discount_amount", "read_only", 1);
        frm.set_df_property("additional_discount_percentage", "read_only", 1);
        frm.set_df_property("price_list", "read_only", 1);

        frappe.msgprint({
            title: "Notice",
            message: "You are a <b>Sales Coordinator</b>. not allowed to apply discounts.",
            indicator: "blue"
        });

    }

    frm.refresh_field("discount_amount");
    frm.refresh_field("additional_discount_percentage");
    frm.refresh_field("price_list");
}
function validateDiscountAmount(frm) {
    if (!frm.canApplyAmountDiscount && frm.doc.discount_amount > 0) {
        frappe.msgprint({
            title: "Permission Error",
            message: "You do not have permission to apply a fixed amount discount!<br>You can only apply a percentage discount.",
            indicator: "red"
        });
        frm.set_value("discount_amount", 0);
        return false;
    }

    if (frm.doc.discount_amount > 0 && frm.doc.net_total) {
        const discountPercentage = (frm.doc.discount_amount / frm.doc.net_total) * 100;

        if (discountPercentage > 20) {
            frappe.msgprint({
                title: "Warning - High Discount",
                message: `The discount amount <b>${frm.doc.discount_amount}</b> represents <b>${discountPercentage.toFixed(2)}%</b> of the total.`,
                indicator: "orange"
            });

        }
    }
}

function validateAdditionalDiscount(frm) {
    if (!frm.maxDiscountPercentageAllowed && frm.maxDiscountPercentageAllowed !== 0) {
        applyDiscountPermissions(frm);
    }

    const additionalDiscount = frm.doc.additional_discount_percentage || 0;
        if (!frm.canApplyDiscount && additionalDiscount > 0) {
        frappe.msgprint({
            title: "Permission Error",
            message: "You do not have permission to apply discounts!",
            indicator: "red"
        });

        frm.set_value("additional_discount_percentage", 0);
        return false;
    }

    if (frm.maxDiscountPercentageAllowed < 100 && additionalDiscount > frm.maxDiscountPercentageAllowed) {
            frappe.msgprint({
                title: "Discount Limit Exceeded",
                message: `<b>Allowed discount limit: ${frm.maxDiscountPercentageAllowed}%</b><br>
                          Requested discount: ${additionalDiscount}%<br><br>
                          Please reduce the discount to the allowed limit.`,
                indicator: "red"
            });


        frm.set_value("additional_discount_percentage", 0);
        return false;
    }

}

function validatePriceListChange(frm) {
    if (!frm.canChangePrice) {
        frappe.msgprint({
            title: "Permission Error",
            message: "You do not have permission to change the Price List!",
            indicator: "red"
        });


        frm.reload_doc();
        return false;
    }
}

function validateDiscountRules(frm) {
    const userRoles = frappe.user_roles;
    const discountAmount = frm.doc.discount_amount || 0;
    const additionalDiscount = frm.doc.additional_discount_percentage || 0;
    const totalDiscount = discountAmount + additionalDiscount;

    console.log({
        user: frappe.session.user,
        roles: userRoles,
        discount_amount: discountAmount,
        additional_discount_percentage: additionalDiscount,
        total_discount: totalDiscount,
        grand_total: frm.doc.grand_total
    });

    if (additionalDiscount > 5) {
        frappe.msgprint({
            title: "High Discount",
            message: `An additional discount of ${additionalDiscount}% has been applied to this quotation.`,
            indicator: "yellow"
        });

    }
}

frappe.ui.form.on("Quotation", {
    onload: function(frm) {
        if (cur_frm.is_dirty()) {
            frm.set_value("transaction_date", frappe.datetime.get_today());
            // valid_till = 7 day + transaction_date
            let valid_till = frappe.datetime.add_days(frappe.datetime.get_today(), 7);
            frm.set_value("valid_till", valid_till);
        }
    }
});
